using System;
using System.Diagnostics;
using SkiaSharp;

const int WIDTH = 1920;
const int HEIGHT = 1080;
const int ITERATIONS = 500;

var gradientPaint = new SKPaint
{
    Shader = SKShader.CreateLinearGradient(
        new SKPoint(0, 0),
        new SKPoint(0, HEIGHT),
        new SKColor[] { SKColors.DarkBlue, SKColors.Black },
        new float[] { 0, 0.75f },
        SKShaderTileMode.Clamp)
};

var solidPaint = new SKPaint { Color = SKColors.DarkBlue };

using var bitmap = new SKBitmap(WIDTH, HEIGHT);
using var canvas = new SKCanvas(bitmap);

for (int i = 0; i < 10; i++)
{
    canvas.DrawRect(0, 0, WIDTH, HEIGHT, gradientPaint);
    canvas.DrawRect(0, 0, WIDTH, HEIGHT, solidPaint);
}

var sw = Stopwatch.StartNew();
for (int i = 0; i < ITERATIONS; i++)
{
    canvas.DrawRect(0, 0, WIDTH, HEIGHT, gradientPaint);
    canvas.Flush();
}
sw.Stop();
var gradientMs = sw.Elapsed.TotalMilliseconds;

sw.Restart();
for (int i = 0; i < ITERATIONS; i++)
{
    canvas.DrawRect(0, 0, WIDTH, HEIGHT, solidPaint);
    canvas.Flush();
}
sw.Stop();
var solidMs = sw.Elapsed.TotalMilliseconds;

var ratio = gradientMs / solidMs;
Console.WriteLine($"SkiaSharp version: {typeof(SKBitmap).Assembly.GetName().Version}");
Console.WriteLine($"Gradient DrawRect: {ITERATIONS} iterations in {gradientMs:F1}ms ({gradientMs/ITERATIONS:F2}ms/iter)");
Console.WriteLine($"Solid DrawRect:    {ITERATIONS} iterations in {solidMs:F1}ms ({solidMs/ITERATIONS:F2}ms/iter)");
Console.WriteLine($"Gradient/Solid ratio: {ratio:F1}x");
Console.WriteLine($"SUCCESS: test completed");

proposedResponse.body:
Thanks for reporting this — we've confirmed the performance regression with gradient shaders.

We benchmarked `DrawRect` with a linear gradient shader (DarkBlue→Black, 1920×1080) at 500 iterations:

| Version | Gradient (ms/iter) | Solid (ms/iter) | Ratio |
|---------|-------------------|-----------------|-------|
| 2.88.9 | 0.17 | 0.16 | 1.1x |
| 3.116.0 | 4.56 | 0.12 | 38.8x |
| 3.119.2 (latest) | 4.62 | 0.12 | 38.8x |
| main (source) | 4.60 | 0.12 | 39.3x |

The gradient shader is ~27x slower per-iteration in v3 compared to v2.88.9. The C# and C API wrappers are trivially thin pass-throughs — the bottleneck is in the upstream Skia raster gradient pipeline which changed between the Skia milestones used in v2 and v3.

**Workarounds:**

1. **Cache the gradient as a bitmap** — pre-render the gradient to an `SKImage` once (when the size changes) and draw the cached image each frame:
```csharp
// Once, when size changes:
using var tempSurface = SKSurface.Create(new SKImageInfo(width, height));
tempSurface.Canvas.DrawRect(0, 0, width, height, BG);
cachedGradient?.Dispose();
cachedGradient = tempSurface.Snapshot();

// In PaintSurface:
canvas.DrawImage(cachedGradient, 0, 0);
```

2. **Use GPU-accelerated rendering** — if you're using `SKCanvasView` (CPU/raster), switching to `SKGLView` (GPU) should significantly improve gradient performance since GPU shaders handle gradients natively.
